class DynamicPSO:
    def __init__(self, problem, initial_positions):
        self.problem = problem
        self.positions = initial_positions
        self.velocities = np.zeros_like(initial_positions)
        self.pbest_positions = initial_positions.copy()
        self.gbest_position = initial_positions[0].copy()
        self.fitness_values = self.evaluate_positions()

    def evaluate_positions(self):
        return np.array([self.problem.evaluate(pos) for pos in self.positions])

    def update_velocities(self, cognitive_coefficient, social_coefficient, inertia_weight):
        r1 = np.random.rand(*self.velocities.shape)
        r2 = np.random.rand(*self.velocities.shape)
        new_velocities = (inertia_weight * self.velocities +
                          cognitive_coefficient * r1 * (self.pbest_positions - self.positions) +
                          social_coefficient * r2 * (self.gbest_position - self.positions))
        self.velocities = new_velocities

    def update_positions(self):
        self.positions += self.velocities
        self.fitness_values = self.evaluate_positions()
        for i in range(len(self.fitness_values)):
            if self.fitness_values[i] < self.problem.evaluate(self.pbest_positions[i]):
                self.pbest_positions[i] = self.positions[i]
            if self.fitness_values[i] < self.problem.evaluate(self.gbest_position):
                self.gbest_position = self.positions[i]

    def optimize(self, max_iterations):
        for _ in range(max_iterations):
            self.update_velocities(1.5, 2.0, 0.7)
            self.update_positions()
        return self.gbest_position

