class ParticleSwarmOptimizer:
    def __init__(self, particles, environment):
        self.particles = particles
        self.environment = environment
        self.switching_threshold = 0.1  # Initial switching threshold

    def update_switching_threshold(self):
        # Update the switching threshold based on performance metrics and environmental conditions
        current_efficiency = self.calculate_efficiency()
        if current_efficiency > 0.95:
            self.switching_threshold *= 0.9  # Reduce threshold for more exploration
        elif current_efficiency < 0.75:
            self.switching_threshold *= 1.1  # Increase threshold to reduce switching

    def optimize(self):
        for particle in self.particles:
            if self.calculate_movement_change(particle) > self.switching_threshold:
                particle.update_direction()
            else:
                particle.continue_current_path()

    def calculate_movement_change(self, particle):
        # Calculate the change in position or velocity
        return abs(particle.velocity - particle.previous_velocity)

    def calculate_efficiency(self):
        # Calculate overall swarm efficiency based on performance metrics
        total_time = sum([particle.time_to_complete_task() for particle in self.particles])
        return 1 / total_time

    def run(self, iterations):
        for _ in range(iterations):
            self.update_switching_threshold()
            self.optimize()

