class TokenManager:
    def __init__(self, num_tokens):
        self.tokens = [0] * num_tokens  # Initialize tokens with zero priority

    def allocate_token(self, task_priority):
        # Find the least prioritized token and assign it to the new task
        min_index = self.tokens.index(min(self.tokens))
        self.tokens[min_index] += task_priority
        return min_index

    def recycle_token(self, token_id):
        # Recycle a token by setting its priority back to zero
        self.tokens[token_id] = 0

