class HierarchicalMemoryModel:
    def __init__(self):
        self.layers = []
        self.weights = {}

    def add_layer(self, layer_size, num_units):
        self.layers.append(layer_size)
        self.weights[layer_size] = {}

    def learn(self, x, y):
        # Forward pass
        hidden_layer = np.dot(x, self.weights['hidden'])
        output_layer = np.dot(hidden_layer, self.weights['output'])

        # Backward pass
        error = y - output_layer
        gradients = np.zeros((len(error), len(output_layer.shape)))
        for i in range(len(gradients)):
            gradients[i] = np.dot(error, self.weights['hidden'][:, i])

        # Weight update
        self.weights['hidden'] += 0.01 * gradients[0]

    def predict(self, x):
        hidden_layer = np.dot(x, self.weights['hidden'])
        output_layer = np.dot(hidden_layer, self.weights['output'])
        return np.argmax(output_layer)

