def calculate_reward(task_complexity, reward_magnitude):
    # Task complexity is weighted (e.g., 0.7 for low complexity, 1.0 for high complexity)
    complexity_weight = 0.7

    # Reward magnitude is also weighted (e.g., 0.3 for moderate reward magnitude, 1.0 for high reward magnitude)
    magnitude_weight = 0.3

    return (complexity_weight * task_complexity + magnitude_weight * reward_magnitude) / (complexity_weight + magnitude_weight)

