# Define an event-driven signaling system using a microservices architecture
class EventDrivenSignaling:
    def __init__(self):
        self.events = {}

    async def register_event(self, name, handler):
        """Register an event handler"""
        if name not in self.events:
            self.events[name] = []
        self.events[name].append(handler)

    async def send_event(self, name, data):
        """Send an event with a given payload"""
        if name in self.events:
            for handler in self.events[name]:
                await handler(data)

