import numpy as np

def calculate_similarity(tasks):
    similarities = []
    for i in range(len(tasks)):
        for j in range(i+1, len(tasks)):
            similarity = 1 - np.cos(np.dot(tasks[i].values(), tasks[j].values())) / (np.linalg.norm(tasks[i].values()) * np.linalg.norm(tasks[j].values()))
            similarities.append(similarity)
    return similarities

