# Probabilistic Inference Module
def bayesian_network(x, y):
    # Define prior probabilities and likelihoods
    prior_x = [0.5]
    prior_y = [0.3]

    # Update probabilities using Bayes' theorem
    x_prob = 0.7 * (x + 0.2) / np.sum([i * j for i, j in zip(prior_x, prior_y)])
    y_prob = 0.4 * (y + 0.5) / np.sum([j * k for j, k in zip(prior_x, prior_y)])

    return x_prob, y_prob

