import pygsp as pg

class KGCompressor(pg.kgruner.KGRuner):
    def __init__(self):
        super(KGCompressor, self).__init__()
        self.g = pg.kgruner.Graph.from_adjacency_matrix(np.array([[0, 1, 0], [1, 0, 1], [0, 1, 0]])))

    def compress(self, x):
        nodes = x.nodes
        edges = x.edges
        compressed_nodes = []
        for node in nodes:
            # Aggregates node representations and predicts relevant combinations
            aggregated_node = pg.kgruner.KGRUAggregator(nodes[node], edges)
            compressed_node = aggregated_node.get_result()
            compressed_nodes.append(compressed_node)

        return torch.tensor(compressed_nodes, dtype=torch.float32)

