import json

class Node:
    def __init__(self):
        self.children = {}
        self.value = None

class HMTree:
    def __init__(self):
        self.root = Node()

    def insert(self, key, value):
        node = self.root
        for char in key:
            if char not in node.children:
                node.children[char] = Node()
            node = node.children[char]
        node.value = value

    def query(self, prefix):
        node = self.root
        result = []
        for char in prefix:
            if char not in node.children:
                return []
            node = node.children[char]
            result.extend([child.value for child in node.children.values()])
        return result

