import numpy as np

class TokenBudgetAllocator:
    def __init__(self, alpha, beta, gamma, delta):
        self.alpha = alpha
        self.beta = beta
        self.gamma = gamma
        self.delta = delta

    def calculate_token_budget(self, reward_magnitude, task_complexity, urgency, protocol_priority):
        token_budget = (self.alpha * reward_magnitude +
                        self.beta * task_complexity +
                        self.gamma * urgency +
                        self.delta * protocol_priority)
        return max(1, int(token_budget))  # Ensure minimum budget of 1

    def update_coefficients(self, new_alpha=None, new_beta=None, new_gamma=None, new_delta=None):
        if new_alpha is not None:
            self.alpha = new_alpha
        if new_beta is not None:
            self.beta = new_beta
        if new_gamma is not None:
            self.gamma = new_gamma
        if new_delta is not None:
            self.delta = new_delta

