class InertiaWeightAdjuster:
    def __init__(self, iterations):
        self.iterations = iterations

    def update(self, particles, token_budgets):
        # Calculate tokens for each particle based on fitness and task urgency
        updated_particles = []
        for particle in particles:
            if particle.fitness > 0:  # Only allocate tokens to particles with positive fitness
                token_allocation = random.uniform(1.0 / len(particle.tokens), self.exploration_rate)
                updated_tokens = {k: v + token_allocation * (v - particle.tokens[k]) for k, v in token_budgets.items()}
            else:
                updated_tokens = {k: v for k, v in token_budgets.items()}

            # Update inertia weights using the allocated tokens
            updated_particles.append(Particle(fitness=particle.fitness, exploration_rate=particle.exploration_rate, tokens=updated_tokens))

        return updated_particles

