class Node:
    def __init__(self, value, children=None):
        self.value = value
        self.children = children if children else []

def hierarchical_compress(memory):
    # Identify top-tier layers (highest-level nodes)
    top_layers = [node for node in memory if len(node.children) > 0]

    # Create a new layer for each top-tier node
    compressed_memory = {}
    for node in top_layers:
        compressed_node = Node(node.value, []
        compressed_memory[node] = compressed_node

    # Recursively compress child nodes
    for child in node.children:
        compressed_child = hierarchical_compress(child)
        compressed_node.children.append(compressed_child)

    return compressed_memory

