        return queue.get()

    def receive_message(self, sender_agent_id, recipient_agent_id):
        # Use a distributed event system like RabbitMQ or Apache Kafka
        queue = threading.Queue()
        thread = threading.Thread(target=self.receive_from_queue, args=(sender_agent_id, recipient_agent_id, queue))
        thread.start()
        return queue.get()

