class HierarchicalMemoryModel:
    def __init__(self):
        # Initialize an empty dictionary to store memories at different levels
        self.memories = {}

    def add_memory(self, level, data):
        """
        Add a memory to the hierarchical model.

        Args:
            level (int): The current level of the hierarchy (1-indexed).
            data (dict): The data associated with the memory.
        """
        # If the level is not in the memories dictionary, create it
        if level not in self.memories:
            self.memories[level] = {}

        # Add the new memory to its corresponding level
        self.memories[level][data['key']] = data

    def compress_memory(self, key):
        """
        Compress a memory by extracting the relevant information.

        Args:
            key (str): The key of the memory to be compressed.

        Returns:
            dict: The compressed memory.
        """
        # Get the associated data from the memories dictionary
        data = self.memories[1][key]

        # Extract the necessary information for compression
        if 'data' in data:
            return {'data': data['data']}
        elif 'data_structure' in data:
            return {'data': [d['data'] for d in data['data_structure']]]
        else:
            raise ValueError("Unsupported data structure")

    def decompress_memory(self, key):
        """
        Decompress a memory by extracting the compressed information.

        Args:
            key (str): The key of the memory to be decompressed.

        Returns:
            dict: The decompressed memory.
        """
        # Get the associated data from the memories dictionary
        data = self.memories[1][key]

        # Extract the necessary information for compression
        if 'data' in data:
