def calculate_token_budget(agent, task_queue):
    # Calculate the total number of tokens based on agent resources
    total_tokens = agent.available_tokens

    # Determine the urgency of tasks in the queue
    urgency_scores = {task: task.urgency for task in task_queue}

    # Calculate a weighted average of urgency scores and task complexity
    weighted_average_urgency = sum(urgency * task.complexity for task, urgency in urgency_scores.items()) / sum(task.complexity for task in task_queue)

    # Allocate tokens based on the weighted average urgency
    token_budget_per_task = total_tokens * (weighted_average_urgency / len(task_queue))

    return {task: token_budget_per_task for task in task_queue}

