import numpy as np

class TokenAllocator:
    def __init__(self, num_nodes, initial_tokens=100):
        self.num_nodes = num_nodes
        self.tokens_per_node = np.full(num_nodes, initial_tokens)
        self.task_weights = np.zeros(num_nodes)

    def calculate_rewards(self, task_complexity):
        return task_complexity * 1.5  # Example reward calculation

    def update_task_weights(self, node_id, complexity):
        self.task_weights[node_id] += self.calculate_rewards(complexity)

    def reallocate_tokens(self):
        total_tokens = np.sum(self.tokens_per_node)
        for i in range(self.num_nodes):
            urgency = self.task_weights[i]
            if urgency > 0:
                tokens_to_allocate = (urgency / sum(self.task_weights)) * total_tokens
                self.tokens_per_node[i] += tokens_to_allocate

    def request_token(self, node_id):
        if self.tokens_per_node[node_id] > 0:
            self.tokens_per_node[node_id] -= 1
            return True
        return False

