class HierarchicalMemory:
    def __init__(self, num_levels):
        self.levels = [{} for _ in range(num_levels)]

    def store(self, key, data, level):
        if 0 <= level < len(self.levels):
            self.levels[level][key] = data

    def retrieve(self, key, level):
        if 0 <= level < len(self.levels):
            return self.levels[level].get(key)
        return None

    def decay_levels(self, decay_factor):
        for level in range(len(self.levels) - 1, -1, -1):
            for key, data in list(self.levels[level].items()):
                new_data = {k: v * decay_factor for k, v in data.items()}
                if any(v == 0 for v in new_data.values()):
                    del self.levels[level][key]
                else:
                    self.store(key, new_data, level)

