class AgentCommunicationProtocol:
    def __init__(self, agents):
        self.agents = agents
        self.token_budgets = {agent: 100 for agent in agents}  # Initial token budget per agent

    def update_token_budgets(self, task_urgency, environmental_feedback):
        for agent in self.agents:
            urgency_factor = self.calculate_urgency_factor(task_urgency[agent])
            feedback_factor = self.calculate_feedback_factor(environmental_feedback[agent])
            new_budget = int(self.token_budgets[agent] * (urgency_factor + feedback_factor) / 2)
            self.token_budgets[agent] = max(1, min(new_budget, 200))  # Clamp between 1 and 200 tokens

    def calculate_urgency_factor(self, urgency):
        return 1 + 0.5 * (urgency - 1)  # Increase budget for more urgent tasks

    def calculate_feedback_factor(self, feedback):
        return 1 + 0.2 * feedback  # Adjust budget based on environmental feedback

