class HierarchicalMemory:
    def __init__(self, max_size, top_threshold=0.7, middle_threshold=0.3):
        self.max_size = max_size
        self.top_threshold = top_threshold
        self.middle_threshold = middle_threshold
        self.top_layer = {}
        self.middle_layer = {}
        self.bottom_layer = {}

    def load_memory(self, memory_file):
        with open(memory_file, 'r') as f:
            self.memory = json.load(f)

    def predict_decay_rate(self, data):
        # Placeholder for a simple decay rate prediction model
        return np.random.rand(len(data))

    def compress_memory(self):
        decay_rates = self.predict_decay_rate(list(self.memory.values()))

        for key, value in zip(self.memory.keys(), decay_rates):
            if value > self.top_threshold:
                if len(self.top_layer) < self.max_size * self.top_threshold:
                    self.top_layer[key] = value
            elif value > self.middle_threshold:
                if len(self.middle_layer) < self.max_size * (self.middle_threshold - self.top_threshold):
                    self.middle_layer[key] = value
            else:
                if len(self.bottom_layer) < self.max_size * (1 - self.middle_threshold):
                    self.bottom_layer[key] = value

    def save_memory(self, memory_file):
        combined_memory = {**self.top_layer, **self.middle_layer, **self.bottom_layer}
        with open(memory_file, 'w') as f:
            json.dump(combined_memory, f)

