class HierarchicalMemory:
    def __init__(self):
        self.root = MemoryNode(None)
        self.tier_levels = {}

    def add_data(self, data, priority):
        if priority not in self.tier_levels:
            self.tier_levels[priority] = MemoryNode(None)
        self._add_data_to_tier(data, self.tier_levels[priority])

    def _add_data_to_tier(self, data, tier_node):
        new_node = MemoryNode(data)
        tier_node.add_child(new_node)

    def get_all_data(self):
        return self._get_all_data_from_node(self.root)

    def _get_all_data_from_node(self, node):
        data_list = []
        for child in node.get_children():
            data_list.extend(self._get_all_data_from_node(child))
            data_list.append(child.get_data())
        return data_list


