class DynamicSwarmSizeAdjuster:
    def __init__(self, initial_size, max_size, min_size):
        self.current_size = initial_size
        self.max_size = max_size
        self.min_size = min_size

    def update Swarm(self, particles, fitness_values):
        if self._should_increase_size(fitness_values):
            self.current_size = min(self.current_size + 1, self.max_size)
        elif self._should_decrease_size(particles):
            self.current_size = max(self.current_size - 1, self.min_size)

    def _should_increase_size(self, fitness_values):
        avg_fitness = sum(fitness_values) / len(fitness_values)
        if avg_fitness > threshold:
            return True
        return False

    def _should_decrease_size(self, particles):
        spread = np.var([p.position for p in particles])
        if spread < threshold:
            return True
        return False

