def multi_objective_pso(swarm, objective_function):
    # Initialize Pareto front
    pareto_front = []

    for particle in swarm:
        fitness_values = objective_function(particle.position)
        if not pareto_front:
            pareto_front.append(particle)
        else:
            is_dominated = False
            for p in pareto_front:
                dominates_current = all(f1 <= f2 for f1, f2 in zip(fitness_values, [p.fitness[i] for i in range(len(fitness_values))]))
                dominated_by_current = any(f1 < f2 for f1, f2 in zip([p.fitness[i] for i in range(len(p.fitness))], fitness_values))
                if dominates_current:
                    is_dominated = True
                    break
                elif dominated_by_current:
                    pareto_front.remove(p)
            if not is_dominated:
                pareto_front.append(particle)

    return pareto_front

class TokenBudgetAllocator:
    def __init__(self, alpha, k):
        self.alpha = alpha  # Weighting factor for Reward Magnitude
        self.k = k          # Constant to determine budget sensitivity

    def calculate_budget(self, reward_magnitude, task_complexity):
        weighted_average = (self.alpha * reward_magnitude) + ((1 - self.alpha) * task_complexity)
        token_budget = self.k * weighted_average
        return max(1, int(token_budget))  # Ensure a minimum budget of at least 1 token

