def allocate_tokens(tasks, total_tokens):
    # Sort tasks by their complexity score in descending order
    sorted_tasks = sorted(tasks, key=lambda x: calculate_task_complexity(x), reverse=True)

    allocations = {}
    remaining_tokens = total_tokens

    for task in sorted_tasks:
        complexity = calculate_task_complexity(task)

        if remaining_tokens >= complexity:
            allocations[task['id']] = complexity
            remaining_tokens -= complexity
        else:
            allocations[task['id']] = remaining_tokens
            remaining_tokens = 0
            break

    return allocations

