import heapq

class AgentCommunicationSystem:
    def __init__(self):
        self.message_queue = []
        self.token_pool = 1000  # Initial pool of tokens
        self.token_threshold = 500  # Token threshold for critical messages

    def assign_token(self, message):
        # Assign token based on message priority
        if message['priority'] == 'high':
            return 10
        elif message['priority'] == 'medium':
            return 5
        else:
            return 2

    def send_message(self, sender, receiver, message):
        token = self.assign_token(message)
        if self.token_pool >= token:
            self.token_pool -= token
            heapq.heappush(self.message_queue, (-token, message))
            print(f"Message sent from {sender} to {receiver}: {message['content']} with token value {token}")
        else:
            print("Not enough tokens available for sending this message")

    def receive_messages(self):
        while self.message_queue:
            _, message = heapq.heappop(self.message_queue)
            print(f"Message received: {message['content']}")
            if self.token_pool < self.token_threshold and message['token_value'] > 10:
                self.token_pool += 5  # Refill tokens for critical messages

    def adjust_tokens(self):
        current_load = sum(1 for _ in self.message_queue)
        if current_load > self.token_threshold:
            self.token_threshold *= 1.2  # Increase token threshold
        elif current_load < self.token_threshold / 2:
            self.token_threshold /= 1.2  # Decrease token threshold

