        self.prior_probabilities = prior_probabilities

    def update_prior(self, new_data):
        # Update prior probabilities based on new data
        posterior_probabilities = {}
        for emotion, prior in self.prior_probabilities.items():
            likelihood = norm.pdf(new_data, loc=prior['mean'], scale=prior['std'])
            posterior_probabilities[emotion] = likelihood * prior['prob']
        return posterior_probabilities

    def predict_outcome(self, posterior_probabilities):
        # Predict the most likely outcome based on updated probabilities
        max_prob_emotion = max(posterior_probabilities, key=posterior_probabilities.get)
        return max_prob_emotion

