class Agent:
    def __init__(self, id):
        self.id = id
        self.priority = 0.5  # Initial priority

    def update_priority(self, reward):
        # Simple linear adjustment based on reward
        self.priority += reward * 0.1
        if self.priority > 1.0:
            self.priority = 1.0
        elif self.priority < 0.0:
            self.priority = 0.0

class PriorityManager:
    def __init__(self):
        self.agents = {}

    def add_agent(self, agent_id):
        self.agents[agent_id] = Agent(agent_id)

    def update_priority(self, agent_id, reward):
        if agent_id in self.agents:
            self.agents[agent_id].update_priority(reward)
